  params: {
    sku: storageSku
    location: location
  }
}

output storageAccountId string = storage.outputs.id

import * as pulumi from "@pulumi/pulumi";
import * as azure from "@pulumi/azure-native";

pulumi.runtime.setMocks({
  newResource: (args) => ({ id: `${args.name}-id`, state: args.inputs }),
  call: (args) => ({ outputs: args.inputs }),
});

import { storageAccount } from "./infra";

test("storage account disallows public blob access", async () => {
  const val = await new Promise<boolean>((resolve) =>
    storageAccount.allowBlobPublicAccess.apply(resolve)
  );
  expect(val).toBe(false);
});

import * as cdk from 'aws-cdk-lib';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as iam from 'aws-cdk-lib/aws-iam';

class StorageStack extends cdk.Stack {
  constructor(scope: cdk.App, id: string) {
    super(scope, id);

    // L1: raw CloudFormation — like a Bicep `resource` block, every prop explicit
    new s3.CfnBucket(this, 'RawBucket', { versioningConfiguration: { status: 'Enabled' } });

    // L2: encryption + public-access block applied by default
    const bucket = new s3.Bucket(this, 'ManagedBucket', { versioned: true });

    // L2 IAM wiring — replaces manual roleAssignment resources in Bicep
    bucket.grantRead(new iam.ArnPrincipal('arn:aws:iam::123456789012:role/Reader'));
  }
}

new StorageStack(new cdk.App(), 'StorageStack');

param keyVaultName string
param secretName string

resource kv 'Microsoft.KeyVault/vaults@2023-07-01' existing = {
  name: keyVaultName
}

resource appService 'Microsoft.Web/sites@2023-01-01' = {
  name: 'my-app'
  location: resourceGroup().location
  properties: {
    siteConfig: {
      appSettings: [
        {
          name: 'DB_PASSWORD'
          value: kv.getSecret(secretName)
        }
      ]
    }
  }
}

// Read-only reference — Bicep does NOT manage this resource
resource sharedKv 'Microsoft.KeyVault/vaults@2023-07-01' existing = {
  name: 'prod-shared-kv'
  scope: resourceGroup('shared-infra-rg')
}

// Bring existing storage account under management (idempotent adoption)
resource storage 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: 'mylegacystorage'
  location: resourceGroup().location
  sku: { name: 'Standard_LRS' }
  kind: 'StorageV2'
  properties: { minimumTlsVersion: 'TLS1_2' }
}

// Safe first-deploy check
// az deployment group create --what-if -g my-rg -f main.bicep

resource storageAccount 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: storageAccountName
  location: location
  sku: { name: 'Standard_LRS' }
  kind: 'StorageV2'
}

resource storageLock 'Microsoft.Authorization/locks@2020-05-01' = {
  name: '${storageAccountName}-delete-lock'
  scope: storageAccount
  properties: {
    level: 'CanNotDelete'
    notes: 'Prevent accidental deletion of production storage.'
  }
}
